import json

def fake_llm(messages):
    if len(messages) == 1:
        return {
            "stop_reason": "tool_use",
            "content": [{
                "type": "tool_use", "id": "toolu_1",
                "name": "read_file",
                "input": {"path": "todo.txt"},
            }],
        }
    return {
        "stop_reason": "end_turn",
        "content": [{"type": "text", "text": "done. todos: write tests"}],
    }

def run_tool(name, args):
    if name == "read_file":
        return "write tests"
    return "unknown tool"

MAX_TURNS = 5
messages = [{"role": "user", "content": "what's on my todo?"}]
log_lines = []

for turn in range(MAX_TURNS):
    response = fake_llm(messages)
    log_lines.append(json.dumps(
        {"turn": turn, "stop_reason": response["stop_reason"]}
    ))

    if response["stop_reason"] == "end_turn":
        print(response["content"][0]["text"])
        break
    block = response["content"][0]
    result = run_tool(block["name"], block["input"])
    log_lines.append(json.dumps(
        {"turn": turn, "tool": block["name"], "result": result}
    ))

    messages.append({"role": "assistant", "content": response["content"]})
    messages.append({"role": "user", "content": [
        {"type": "tool_result",
         "tool_use_id": block["id"],
         "content": result},
    ]})

print(f"log entries: {len(log_lines)}")
